// AppScope shell — owns all UI state and routes between views.
// Ported from the Component class in AppScope.dc.html (state + renderVals).
import { useMemo, useState } from "react";
import { buildAppData } from "./data/mockData";
import { fmtSize } from "./lib/format";
import TitleBar from "./components/TitleBar";
import StatusBar from "./components/StatusBar";
import Sidebar from "./components/Sidebar";
import FlowTable from "./components/FlowTable";
import EmptyState from "./components/EmptyState";
import AppDetail from "./components/AppDetail";
import CertManager from "./components/CertManager";
import Settings, { type Toggles } from "./components/Settings";
import AddPageModal from "./components/modals/AddPageModal";
import AddAppModal from "./components/modals/AddAppModal";
import CertGuideModal from "./components/modals/CertGuideModal";

type NavMode = "sessions" | "certs" | "settings";
type ModalKind = null | "addPage" | "addApp" | "certGuide";

export default function App() {
  const D = useMemo(() => buildAppData(), []);

  const [navMode, setNavMode] = useState<NavMode>("sessions");
  const [activeId, setActiveId] = useState("acme");
  const [variant, setVariant] = useState<"A" | "B">("A");
  const [filter, setFilter] = useState("all");
  const [query, setQuery] = useState("");
  const [recording, setRecording] = useState(true);
  const [modal, setModal] = useState<ModalKind>(null);
  const [clear, setClear] = useState<Record<string, boolean>>({});
  const [selectedFlowId, setSelectedFlowId] = useState<string | null>(D.defaultSel);
  const [launchMode, setLaunchMode] = useState("normal");
  const [toggles, setToggles] = useState<Toggles>({ mask: true, quic: true, login: false, autoclean: true });

  const find = (id: string) => D.pages.find((p) => p.id === id) || D.apps.find((a) => a.id === id);
  const isAppId = (id: string) => !!D.apps.find((a) => a.id === id);
  const activeFlows = (id?: string) => {
    const a = id || activeId;
    if (isAppId(a)) return [];
    const p = D.pages.find((pg) => pg.id === a);
    if (!p) return [];
    return clear[a] ? [] : p.flows;
  };
  const firstId = (id: string): string | null => {
    const f = activeFlows(id);
    if (!f.length) return null;
    return f.find((x) => x.id === D.defaultSel) ? D.defaultSel : f[0].id;
  };

  const selectSession = (id: string) => {
    const app = isAppId(id);
    setNavMode("sessions");
    setActiveId(id);
    if (!app) setSelectedFlowId(firstId(id));
  };

  const active = find(activeId);
  const isApp = isAppId(activeId);
  const sessionsMode = navMode === "sessions";
  const flows = activeFlows();

  const totalCount = String(D.pages.reduce((a, p) => a + (clear[p.id] ? 0 : p.flows.length), 0));
  const titleSuffix = navMode === "certs" ? "Certificates" : navMode === "settings" ? "Settings" : active ? active.name : "AppScope";

  const done = flows.filter((f) => f.status != null);
  const xfer = done.reduce((a, f) => a + (f.size || 0), 0);
  const statusLeft = isApp
    ? active
      ? `${active.name} · Normal launch`
      : ""
    : flows.length
    ? `${flows.length} requests · ${fmtSize(xfer)} transferred · finish 2.7 s`
    : "Idle — no requests";

  const clearFlows = () => {
    setClear((c) => ({ ...c, [activeId]: true }));
    setSelectedFlowId(null);
  };
  const toggle = (k: keyof Toggles) => setToggles((t) => ({ ...t, [k]: !t[k] }));

  const showApp = sessionsMode && isApp;
  const showEmpty = sessionsMode && !isApp && flows.length === 0;
  const showFlows = sessionsMode && !isApp && flows.length > 0;

  return (
    <div
      style={{
        minHeight: "100vh",
        width: "100%",
        boxSizing: "border-box",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 32,
        background: "linear-gradient(160deg,#dcdde1,#cbccd2)",
        fontFamily: "-apple-system,BlinkMacSystemFont,'SF Pro Text',system-ui,sans-serif",
      }}
    >
      <div
        style={{
          width: 1280,
          height: 808,
          background: "#ffffff",
          borderRadius: 11,
          boxShadow: "0 28px 70px rgba(0,0,0,.32),0 2px 8px rgba(0,0,0,.18)",
          overflow: "hidden",
          display: "flex",
          flexDirection: "column",
          border: "0.5px solid rgba(0,0,0,.18)",
        }}
      >
        <TitleBar titleSuffix={titleSuffix} variant={variant} onVariant={setVariant} />

        <div style={{ flex: 1, display: "flex", minHeight: 0 }}>
          <Sidebar
            pages={D.pages}
            apps={D.apps}
            navMode={navMode}
            activeId={activeId}
            totalCount={totalCount}
            query={query}
            onQuery={setQuery}
            onSelectAll={() => selectSession("acme")}
            onSelect={selectSession}
            onAddPage={() => setModal("addPage")}
            onAddApp={() => setModal("addApp")}
            onCerts={() => setNavMode("certs")}
            onSettings={() => setNavMode("settings")}
          />

          <div style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", minHeight: 0, background: "#ffffff" }}>
            {navMode === "certs" && <CertManager onOpenGuide={() => setModal("certGuide")} />}
            {navMode === "settings" && <Settings toggles={toggles} onToggle={toggle} />}
            {showApp && active && "bundle" in active && (
              <AppDetail app={active} launchMode={launchMode} onLaunchMode={setLaunchMode} />
            )}
            {showEmpty && <EmptyState />}
            {showFlows && (
              <FlowTable
                flows={flows}
                variant={variant}
                showWaterfall
                query={query}
                filter={filter}
                selectedId={selectedFlowId}
                recording={recording}
                onSelect={setSelectedFlowId}
                onQuery={setQuery}
                onFilter={setFilter}
                onToggleRecord={() => setRecording((r) => !r)}
                onClear={clearFlows}
              />
            )}
          </div>
        </div>

        <StatusBar statusLeft={statusLeft} live={recording && flows.length > 0} />
      </div>

      {/* modal overlay */}
      {modal != null && (
        <div
          onClick={() => setModal(null)}
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(20,20,24,.34)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 50,
            backdropFilter: "blur(1.5px)",
          }}
        >
          {modal === "addPage" && <AddPageModal onClose={() => setModal(null)} onOpenCertGuide={() => setModal("certGuide")} />}
          {modal === "addApp" && <AddAppModal onClose={() => setModal(null)} />}
          {modal === "certGuide" && <CertGuideModal onClose={() => setModal(null)} />}
        </div>
      )}
    </div>
  );
}

